const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.PAYMENT_QUEUE || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

async function chargeCard(payment) {
  console.log('Charging card', {
    paymentId: payment.paymentId,
    customerId: payment.customerId,
    amount: payment.amount,
    currency: payment.currency,
    cardToken: payment.cardToken,
  });

  await new Promise((resolve) => setTimeout(resolve, 300));

  return {
    status: 'succeeded',
    transactionId: `txn_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`,
    processedAt: new Date().toISOString(),
  };
}

async function refundPayment(payment) {
  console.log('Refunding payment', {
    paymentId: payment.paymentId,
    transactionId: payment.transactionId,
    amount: payment.amount,
    reason: payment.reason,
  });

  await new Promise((resolve) => setTimeout(resolve, 300));

  return {
    status: 'refunded',
    refundId: `ref_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`,
    processedAt: new Date().toISOString(),
  };
}

async function handlePaymentEvent(event) {
  if (!event || typeof event !== 'object') {
    throw new Error('Invalid event payload');
  }

  switch (event.type) {
    case 'payment.charge':
      return chargeCard(event);
    case 'payment.refund':
      return refundPayment(event);
    default:
      throw new Error(`Unsupported event type: ${event.type}`);
  }
}

async function startConsumer() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, {
    durable: true,
  });

  await channel.prefetch(PREFETCH);

  console.log(`Listening for payment events on queue "${QUEUE_NAME}"`);

  channel.consume(
    QUEUE_NAME,
    async (msg) => {
      if (!msg) return;

      try {
        const raw = msg.content.toString('utf8');
        const event = JSON.parse(raw);

        console.log('Received payment event', event);

        const result = await handlePaymentEvent(event);

        console.log('Payment event processed', {
          type: event.type,
          paymentId: event.paymentId,
          result,
        });

        channel.ack(msg);
      } catch (error) {
        console.error('Failed to process payment event', error);
        channel.nack(msg, false, false);
      }
    },
    { noAck: false }
  );

  const shutdown = async () => {
    console.log('Shutting down consumer...');
    try {
      await channel.close();
    } catch (_) {}
    try {
      await connection.close();
    } catch (_) {}
    process.exit(0);
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);

  connection.on('error', (err) => {
    console.error('RabbitMQ connection error', err);
  });

  connection.on('close', () => {
    console.error('RabbitMQ connection closed');
    process.exit(1);
  });
}

startConsumer().catch((err) => {
  console.error('Consumer failed to start', err);
  process.exit(1);
});